const SELF_HOSTED_REGISTRATION_LOCK_ID = 1431520590;

export class SelfHostedRegistrationError extends Error {
  constructor() {
    super("A team invitation is required to create an account");
    this.name = "SelfHostedRegistrationError";
  }
}

export async function canRegisterSelfHostedUser(
  email?: string | null,
  account?: Pick<Account, "provider" | "providerAccountId"> | null,
) {
  if (env.NEXT_PUBLIC_IS_CLOUD) {
    return true;
  }

  if (account) {
    const existingAccount = await db.account.findUnique({
      where: {
        provider_providerAccountId: {
          provider: account.provider,
          providerAccountId: account.providerAccountId,
        },
      },
      select: { id: true },
    });

    if (existingAccount) {
      return true;
    }
  }

  if (email) {
    const existingUser = await db.user.findUnique({
      where: { email },
      select: { id: true },
    });

    if (existingUser) {
      return true;
    }
  }

  const firstUser = await db.user.findFirst({
    select: { id: true },
  });

  if (!firstUser) {
    return true;
  }

  if (!email) {
    return false;
  }

  const invite = await db.teamInvite.findFirst({
    where: { email },
    select: { id: true },
  });

  return Boolean(invite);
import { beforeEach, describe, expect, it, vi } from "vitest";

const mocks = vi.hoisted(() => {
  const env = {
    GITHUB_ID: "github-client-id",
    GITHUB_SECRET: "github-client-secret",
    NEXT_PUBLIC_IS_CLOUD: true,
  };

  const baseCreateUser = vi.fn();
  const accountFindUnique = vi.fn();
  const userFindUnique = vi.fn();
  const userFindFirst = vi.fn();
  const inviteFindFirst = vi.fn();
  const transactionUserFindFirst = vi.fn();
  const transactionInviteFindFirst = vi.fn();
  const transactionUserCreate = vi.fn();
  const executeRaw = vi.fn();
  const transaction = vi.fn(async (callback) =>
    callback({
      $executeRaw: executeRaw,
      user: {
        findFirst: transactionUserFindFirst,
        create: transactionUserCreate,
      },
      teamInvite: {
        findFirst: transactionInviteFindFirst,
      },
    }),
  );

  return {
    env,
    baseCreateUser,
    accountFindUnique,
    userFindUnique,
    userFindFirst,
    inviteFindFirst,
    transactionUserFindFirst,
    transactionInviteFindFirst,
    transactionUserCreate,
    executeRaw,
    transaction,
  };
});

vi.mock("next-auth", () => ({
