import { afterAll, afterEach, beforeEach, describe, expect, it } from "vitest";
import { AuthHandler } from "next-auth/core";
import type { NextAuthOptions } from "next-auth";
import GitHubProvider from "next-auth/providers/github";

import { env } from "~/env";
import { authOptions } from "~/server/auth";
import { db } from "~/server/db";
import {
  closeIntegrationConnections,
  integrationEnabled,
  resetDatabase,
} from "~/test/integration/helpers";

const describeIntegration = integrationEnabled ? describe : describe.skip;
const AUTH_ORIGIN = "http://localhost:3000/api/auth";

function testGitHubProvider(providerAccountId: string) {
  return GitHubProvider({
    clientId: "test-github-client-id",
    clientSecret: "test-github-client-secret",
    checks: [],
    token: {
      url: "https://github.test/login/oauth/access_token",
      async request() {
        return {
          tokens: {
            access_token: `token-${providerAccountId}`,
            token_type: "bearer",
          },
        };
      },
    },
    userinfo: {
      url: "https://github.test/user",
      async request() {
        return {
          id: Number(providerAccountId),
          login: `github-user-${providerAccountId}`,
          name: null,
          email: null,
          avatar_url: "https://github.test/avatar.png",
        };
      },
    },
  });
}

function optionsForGitHubUser(
  providerAccountId: string,
  signIn: NonNullable<NextAuthOptions["callbacks"]>["signIn"] =
    authOptions.callbacks?.signIn,
): NextAuthOptions {
  return {
    ...authOptions,
    callbacks: {
      ...authOptions.callbacks,
      signIn,
    },
    providers: [testGitHubProvider(providerAccountId)],
  };
}

async function runGitHubCallback(options: NextAuthOptions) {
  return AuthHandler({
    req: {
      action: "callback",
      providerId: "github",
      method: "GET",
      origin: AUTH_ORIGIN,
      headers: { host: "localhost:3000" },
      query: { code: "test-authorization-code" },
      cookies: {},
    },
    options,
  });
}

describeIntegration("self-hosted GitHub authentication integration", () => {
  beforeEach(async () => {
    env.NEXT_PUBLIC_IS_CLOUD = false;
    await resetDatabase();
  });

  afterEach(() => {
    env.NEXT_PUBLIC_IS_CLOUD = true;
  });

  afterAll(async () => {
    await closeIntegrationConnections();
  });

  it("reproduces the 1.9.5 denial and completes the fixed no-email OAuth flow", async () => {
    const legacyResponse = await runGitHubCallback(
      optionsForGitHubUser("101", async ({ user }) => Boolean(user.email)),
    );

    expect(legacyResponse.redirect).toBe(
      `${AUTH_ORIGIN}/error?error=AccessDenied`,
    );
    await expect(db.user.count()).resolves.toBe(0);

    const firstLogin = await runGitHubCallback(optionsForGitHubUser("101"));

    expect(firstLogin.redirect).toBe("http://localhost:3000");
    expect(firstLogin.cookies).toEqual(
      expect.arrayContaining([
        expect.objectContaining({ name: "next-auth.session-token" }),
      ]),
    );
    await expect(db.user.count()).resolves.toBe(1);
    await expect(db.account.count()).resolves.toBe(1);
    await expect(db.session.count()).resolves.toBe(1);
    await expect(
      db.account.findUnique({
        where: {
          provider_providerAccountId: {
            provider: "github",
            providerAccountId: "101",
          },
        },
        include: { user: true },
      }),
    ).resolves.toMatchObject({
      provider: "github",
      providerAccountId: "101",
      user: { email: null },
    });

    const repeatLogin = await runGitHubCallback(optionsForGitHubUser("101"));

    expect(repeatLogin.redirect).toBe("http://localhost:3000");
    await expect(db.user.count()).resolves.toBe(1);
    await expect(db.account.count()).resolves.toBe(1);
    await expect(db.session.count()).resolves.toBe(2);

    const uninvitedLogin = await runGitHubCallback(
      optionsForGitHubUser("202"),
    );

    expect(uninvitedLogin.redirect).toBe(
      `${AUTH_ORIGIN}/error?error=AccessDenied`,
    );
    await expect(db.user.count()).resolves.toBe(1);
    await expect(db.account.count()).resolves.toBe(1);
  });
});

